import{_ as s,c as a,o as i,d}from"./plugin-vue_export-helper.d4b2cde8.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 15","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 15","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-07-30T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/15.md","lastUpdated":1625430706000}',c={},n=d('<div class="stanza"><a href="#s15.1" id="s15.1" class="num">15.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0434\u0445\u0430\u0440\u0430\u043D, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043E\u0440\u0433\u0430\u043D\u0430 \u0440\u0435\u0447\u0438 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0443\u043C\u043E\u043C .</p></div><div class="stanza"><a href="#s15.2" id="s15.2" class="num">15.2</a><p>\u041F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0441\u0435\u0431\u044F, (\u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F) \u043F\u043E\u0441\u043B\u0435 \xAB\u0432\u0430\u0447\u0430\u043D\u044B\xBB \u0441\u043B\u043E\u0432\u043E \u041D\u0410\u041C\u0410\u0425, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u043C\u043E\u043B\u0447\u0430 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u043C\u0443\u044E \u0440\u0435\u0447\u044C .</p></div><div class="stanza"><a href="#s15.3" id="s15.3" class="num">15.3</a><p>\u0423 \u043D\u0435\u0433\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u0435\u0442 \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u0430\u044F \u0440\u0435\u0447\u044C \u043F\u043E\u0432\u0441\u044E\u0434\u0443. \u0417\u0430 \u0433\u043E\u0434 \u0443 \u043D\u0435\u0433\u043E \u0431\u0443\u0434\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0432\u0441\u0435\u0445 \u0448\u0430\u0441\u0442\u0440 .</p></div><div class="stanza"><a href="#s15.4" id="s15.4" class="num">15.4</a><p>\u0423 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0440\u0435\u0447\u044C, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0443\u0440\u0430\u0448\u0435\u043D\u0438\u044F\u043C\u0438, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0441\u0430\u043C \u0430\u0432\u0442\u043E\u0440\u043E\u043C \u0448\u0430\u0441\u0442\u0440 .</p></div><div class="stanza"><a href="#s15.5" id="s15.5" class="num">15.5</a><p>\u0422\u0430\u043C \u0436\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E (\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E) \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044E. \u041F\u0443\u0441\u0442\u044C \u043E\u043D\u043E \u0431\u0443\u0434\u0435\u0442 \u043F\u044B\u043B\u0430\u044E\u0449\u0438\u043C, \u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0438\u043C \u043E\u0433\u043D\u0435\u043C .</p></div><div class="stanza"><a href="#s15.6" id="s15.6" class="num">15.6</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0438 \u0432\u043A\u0443\u0441\u0430 \u0438 \u0432\u043D\u0443\u0442\u0440\u0438 \u043E\u0433\u043D\u044F \u0434\u0438\u0441\u043A \u043B\u0443\u043D\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0442\u043E\u0433\u0434\u0430 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B, \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0440\u0435\u0447\u0438 .</p></div><div class="stanza"><a href="#s15.7" id="s15.7" class="num">15.7</a><p>\u041F\u043E\u043C\u0435\u0441\u0442\u0438\u0432 \u043D\u0430 \u0436\u0438\u0432\u043E\u0442 \u043B\u0430\u0434\u043E\u043D\u0438, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u044C, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, (\u0442\u0443) \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u2013 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u043E\u043A\u0435\u0430\u043D .</p></div><div class="stanza"><a href="#s15.8" id="s15.8" class="num">15.8</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0435\u0435, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u0443\u044E \u043D\u0430 \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C (\u043C\u0438\u0440\u043E\u0432) \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0443\u044E \u0442\u0435\u043B\u043E, \u0446\u0432\u0435\u0442\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u0443\u044E \u043B\u043E\u0442\u043E\u0441\u0443, \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u0438 \u0442.\u0434 .</p></div><div class="stanza"><a href="#s15.9" id="s15.9" class="num">15.9</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u043C\u0443 \u0440\u0430\u043D\u0435\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u0443 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B, (\u043A\u043E\u0442\u043E\u0440\u044B\u0435) \u0431\u0443\u0434\u0443\u0442 \u0443\u043C\u0435\u0449\u0430\u0442\u044C\u0441\u044F \u0432 \u0435\u0433\u043E \u0440\u0443\u043A\u0430\u0445 .</p></div><div class="stanza"><a href="#s15.10" id="s15.10" class="num">15.10</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0441\u0442\u043E\u043F\u044B, \u0441\u0442\u0430\u0432 \u0432\u043C\u0435\u0449\u0430\u044E\u0449\u0438\u043C \u043E\u043A\u0435\u0430\u043D \u043E\u043D \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u043C\u0443\u0445\u0443\u0440\u0442\u044B \u0441\u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u043E\u0433\u043D\u0443\u0442\u044C \u0437\u0435\u043C\u043B\u044E .</p></div><div class="stanza"><a href="#s15.11" id="s15.11" class="num">15.11</a><p>\u041F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044F \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0438 \u043F\u043E\u0447\u0438\u0442\u0430\u044F \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u0438 \u043C\u0438\u0440\u043E\u0432 \u0432 \u0441\u0432\u043E\u0435\u043C \u0442\u0435\u043B\u0435, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F (\u0432\u043E \u0432\u0441\u0435\u043C \u0442\u0435\u043B\u0435), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E \u0441\u0442\u043E\u043F .</p></div><div class="stanza"><a href="#s15.12" id="s15.12" class="num">15.12</a><p>\u0421\u0434\u0435\u043B\u0430\u0432 \u0443\u043C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u0432 \u0432\u043E\u0434\u0435 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043C\u0430\u043D\u0430\u0441\u0430 \u0442\u0430\u0442\u0442\u0432\u0443, \u0437\u0430 \u043C\u0435\u0441\u044F\u0446, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u043E\u0442 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432 \u043D\u0435\u0439 \u043E\u043F\u043E\u0440\u0443 \u0438 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043E \u0441 \u043D\u0435\u0439 .</p></div><div class="stanza"><a href="#s15.13" id="s15.13" class="num">15.13</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0443\u0441\u0438\u043B\u0438\u0439, \u043E\u043D, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0441\u043B\u0430\u0432\u0443 \u0432\u043E\u0441\u043F\u0435\u0432\u0430\u0435\u043C\u0443\u044E \u0431\u043B\u0430\u0433\u0438\u043C\u0438 \u0441\u0442\u0438\u0445\u0430\u043C\u0438, \u0438 \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0432\u0438\u0434\u043E\u0432 \u043F\u043B\u043E\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s15.14" id="s15.14" class="num">15.14</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u043C\u0435\u0441\u044F\u0446\u0430, \u043F\u043E\u0431\u0435\u0434\u0438\u0432 \u0447\u0443\u0432\u0441\u0442\u0432\u0430, \u043B\u0438\u043D\u0433\u0430\u043C \u0432 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043D\u0435\u043E\u0442\u0441\u0442\u0443\u043F\u043D\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435, \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u0448\u0435\u0441\u0442\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 \u043F\u043E (\u0441\u0432\u043E\u0435\u0439) \u0432\u043E\u043B\u0435 .</p></div><div class="stanza"><a href="#s15.15" id="s15.15" class="num">15.15</a><p>\u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u043C\u0443\u0434\u0440\u0435\u0446, \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439 \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0432\u0438\u0434\u043E\u0432 (\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0439), \u043E\u0431\u0440\u0435\u0442\u0435\u0442, \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u043B\u0438\u043D\u0433\u0438 .</p></div><div class="stanza"><a href="#s15.16" id="s15.16" class="num">15.16</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u044F\u0437\u044B\u043A, \u0441\u0438\u044F\u044E\u0449\u0438\u0439 \u043A\u0430\u043A \u043B\u0443\u043D\u0430. \u0427\u0435\u0440\u0435\u0437 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u044F\u0437\u044B\u043A\u0430 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0439 \u0410\u0442\u043C\u0430\u043D\u0443 .</p></div><div class="stanza"><a href="#s15.17" id="s15.17" class="num">15.17</a><p>\u041E\u043D \u0431\u0443\u0434\u0435\u0442 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0431\u043E\u0432\u0430\u0442\u044C (\u0432\u0441\u0435), \u0447\u0442\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0434\u0430\u043B\u0435\u043A\u043E, \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 (\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044F) \u0441 \u043E\u0434\u043D\u043E\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u043B\u0438\u0437\u043D\u0443\u0442\u044C \u0432\u044B\u0441\u0448\u0443\u044E \u0430\u043C\u0440\u0438\u0442\u0443 .</p></div><div class="stanza"><a href="#s15.18" id="s15.18" class="num">15.18</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0439, \u0439\u043E\u0433\u0438\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0438 \u0441\u043C\u0435\u0440\u0442\u0438. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u043C\u0443 \u043F\u0438\u0442\u0438\u044E \u0438 \u043F\u0440\u043E\u0447\u0435\u043C\u0443, \u043E\u043D \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D \u0433\u0440\u0435\u0445\u0430\u043C .</p></div><div class="stanza"><a href="#s15.19" id="s15.19" class="num">15.19</a><p>\u041A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435, \u0432\u0441\u0435 \u044D\u0442\u043E \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0432 \u0441\u0432\u043E\u0435\u043C \u0442\u0435\u043B\u0435, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F \u043F\u043B\u043E\u0434\u0430, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432\u043A\u0443\u0441\u0430 .</p></div><div class="stanza"><a href="#s15.20" id="s15.20" class="num">15.20</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442) \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u043D\u043E\u0441 \u0446\u0432\u0435\u0442\u0430 \u0437\u043E\u043B\u043E\u0442\u0430, (\u0442\u043E\u0433\u0434\u0430) \u0437\u0430 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439, \u043E\u043F\u044B\u0442 \u043E\u0431\u043E\u043D\u044F\u043D\u0438\u044F \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u0443\u0441\u0442\u043E\u0442\u043D\u044B\u043C .</p></div><div class="stanza"><a href="#s15.21" id="s15.21" class="num">15.21</a><p>\u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 (\u0439\u043E\u0433\u0438\u043D) \u0441\u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u043E\u043D\u044F\u0442\u044C \u0437\u0430\u043F\u0430\u0445\u0438 \u0432\u0435\u0449\u0435\u0439, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0445 \u0434\u0430\u043B\u0435\u043A\u043E. \u041E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0442\u044C \u0437\u0430\u043F\u0430\u0445, \u0435\u0441\u043B\u0438 \u0442\u043E\u0442 \u0431\u0443\u0434\u0435\u0442 \u043D\u0435\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u043C .</p></div><div class="stanza"><a href="#s15.22" id="s15.22" class="num">15.22</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0439\u043E\u0433\u0443 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0430\u0440\u043E\u043C\u0430\u0442. \u041B\u0438\u0448\u0435\u043D\u043D\u044B\u0439 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0438 \u0441\u043C\u0435\u0440\u0442\u0438, \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u0434\u043E\u0441\u0442\u043E\u0438\u043D (\u043E\u0431\u0440\u0435\u0441\u0442\u0438) \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C .</p></div><div class="stanza"><a href="#s15.23" id="s15.23" class="num">15.23</a><p>\u0412\u0441\u0435, \u0447\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0438\u043C, \u0432\u0441\u0435 \u044D\u0442\u043E \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C. \u0422\u0430\u043A \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043B\u043E\u0434 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u043E\u0431\u043E\u043D\u044F\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s15.24" id="s15.24" class="num">15.24</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u043E\u0438 \u0433\u043B\u0430\u0437\u0430, \u0441\u0438\u044F\u044E\u0449\u0438\u0435 \u0446\u0432\u0435\u0442\u043E\u043C \u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u0441\u043E\u043B\u043D\u0446\u0430, \u0437\u0430 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u043F\u043E\u0442\u043E\u043A\u0430 \u043A\u0440\u043E\u0432\u0438 \u0438\u0437 \u0433\u043B\u0430\u0437 .</p></div><div class="stanza"><a href="#s15.25" id="s15.25" class="num">15.25</a><p>\u0412 \u0435\u0433\u043E \u043B\u0431\u0443 \u044F\u0432\u0438\u0442\u0441\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435. \u041D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0438 \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u0442\u044C \u043D\u0438 \u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0442\u044C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443, \u043E \u0412\u0435\u043B\u0438\u043A\u0430\u044F \u0414\u0435\u0432\u0438!</p></div><div class="stanza"><a href="#s15.26" id="s15.26" class="num">15.26</a><p>\u041E\u0441\u0442\u0430\u0432\u0438\u0432\u0448\u0438\u0439 \u0435\u0433\u043E, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0441\u043B\u0435\u043F\u043E\u0442\u0443, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0443\u0441\u0435\u0440\u0434\u043D\u043E. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s15.27" id="s15.27" class="num">15.27</a><p>\u041C\u0443\u0434\u0440\u044B\u0439 \u0442\u043E\u043D\u043A\u043E \u0431\u0443\u0434\u0435\u0442 \u0432\u0438\u0434\u0435\u0442\u044C \u043D\u0435\u0443\u0441\u044B\u043F\u043D\u043E \u0437\u0435\u043C\u043B\u044E, \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0430\u0434\u0430 \u0438 \u0432\u0432\u0435\u0440\u0445, \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0434\u0445\u0440\u0443\u0432\u044B (<em>\u043F\u043E\u043B\u044F\u0440\u043D\u043E\u0439 \u0437\u0432\u0435\u0437\u0434\u044B</em>), \u043A\u0430\u043A \u043D\u0430 \u043B\u0430\u0434\u043E\u043D\u0438 .</p></div><div class="stanza"><a href="#s15.28" id="s15.28" class="num">15.28</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0439\u043E\u0433\u0438\u043D \u0431\u0443\u0434\u0435\u0442 \u0432\u0438\u0434\u0435\u0442\u044C \u043A\u0440\u0430\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0430 \u043F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 \u0439\u043E\u0433\u0438\u043D\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u0442\u0435\u043B\u0435 .</p></div><div class="stanza"><a href="#s15.29" id="s15.29" class="num">15.29</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u043F\u0440\u0435\u0436\u0434\u0435, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0432\u0441\u0435, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u043E \u0433\u043B\u0430\u0437\u043E\u043C. \u0427\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u0435\u0439?</p></div><div class="stanza"><a href="#s15.30" id="s15.30" class="num">15.30</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0435\u043C\u0443 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u043C\u0435\u0441\u044F\u0446\u0430, \u043D\u0435\u0432\u043E\u0437\u043C\u0443\u0442\u0438\u043C\u043E, \u043A\u043E\u0436\u0443, \u0446\u0432\u0435\u0442\u0430 \u043A\u0430\u043A \u0440\u0443\u043C\u044F\u043D\u044B\u0435 \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0438, \u043D\u0438\u043A\u0442\u043E \u0434\u0430\u0436\u0435 \u043E\u0440\u0443\u0436\u0438\u0435\u043C \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u0447\u0438\u043D\u0438\u0442\u044C \u0432\u0440\u0435\u0434 .</p></div><div class="stanza"><a href="#s15.31" id="s15.31" class="num">15.31</a><p>\u0427\u0435\u0440\u0435\u0437 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u0434\u0430\u0436\u0435 \u043E\u0441\u0442\u0440\u044B\u043C (\u043E\u0440\u0443\u0436\u0438\u0435\u043C) \u0438 \u043E\u0433\u043D\u0435\u043C \u043E\u043D \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0441\u043E\u0436\u0436\u0435\u043D. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0439\u043E\u0433\u0438\u043D (\u0441\u0442\u0430\u043D\u0435\u0442 \u043D\u0435\u0443\u044F\u0437\u0432\u0438\u043C) \u043C\u043E\u043B\u043D\u0438\u0435\u0439, \u043A\u0430\u043C\u043D\u0435\u043C, \u044F\u0434\u043E\u043C \u0438 \u043F\u0440\u043E\u0447\u0438\u043C</p></div><div class="stanza"><a href="#s15.32" id="s15.32" class="num">15.32</a><p>\u041E\u043D \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0440\u0430\u0436\u0435\u043D, \u044F\u0432\u043B\u044F\u044F\u0441\u044C \u043D\u0435\u0441\u0442\u0430\u0440\u0435\u044E\u0449\u0438\u043C \u0438 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u044B\u043C. \u0417\u043D\u0430\u043D\u0438\u0435, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u043E\u0442 \u043E\u0441\u044F\u0437\u0430\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043F\u0435\u0441\u043D\u0435 \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0440\u0438\u0447\u043D\u043E .</p></div><div class="stanza"><a href="#s15.33" id="s15.33" class="num">15.33</a><p>\u0415\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0432\u043C\u0435\u0441\u0442\u0435 \u043F\u043B\u043E\u0434\u0430\u043C\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0438\u0437\u0434\u0440\u0435\u0432\u043B\u0435, \u0438 \u0438\u043C\u0435\u043D\u043D\u043E \u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u043A\u0430\u043A) \u0442\u0435\u043B\u043E, \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 .</p></div><div class="stanza"><a href="#s15.34" id="s15.34" class="num">15.34</a><p>\u0423 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0432\u043E\u0439 \u0443\u043C \u043D\u0430 \u0437\u0432\u0443\u043A\u0435 \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435 \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 \u0437\u0432\u0443\u043A\u043E\u0432, \u0441\u043B\u044B\u0448\u0438\u043C\u044B\u0445 \u0432\u0434\u0430\u043B\u0435\u043A\u0435 .</p></div><div class="stanza"><a href="#s15.35" id="s15.35" class="num">15.35</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430, \u043E \u0414\u0435\u0432\u0438, \u043E\u043D \u043F\u043E\u0434\u043D\u0438\u043C\u0435\u0442\u0441\u044F \u043A \u043A\u0440\u0430\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u041B\u0438\u0448\u0435\u043D\u043D\u044B\u0439 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0438 \u0441\u043C\u0435\u0440\u0442\u0438 \u043E\u043D \u0432\u0441\u0435 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u044B\u0448\u0430\u0442\u044C \u043E\u0442\u0447\u0435\u0442\u043B\u0438\u0432\u043E .</p></div><div class="stanza"><a href="#s15.36" id="s15.36" class="num">15.36</a><p>\u0422\u0430\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0435, \u0442\u0435\u043B\u043E \u043F\u0440\u043E\u0447\u0435\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u043C\u043E\u043C\u0443 \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435. \u0422\u043E\u0433\u0434\u0430 \u043E\u043D, \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B, \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0435\u043C \u0441\u043B\u0443\u0445\u0430 .</p></div><div class="stanza"><a href="#s15.37" id="s15.37" class="num">15.37</a><p>\u041F\u043E\u0432\u0435\u0434\u0430\u044E \u0434\u0445\u0430\u0440\u0430\u043D\u0443 \u0443\u043C\u0430, \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0443\u044E \u0432\u0441\u0435\u043C\u0438 \u0441\u0438\u0434\u0434\u0445\u0438, \u043E\u0431\u0440\u0435\u0442\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u0432 \u043D\u0435\u0439, \u043E \u0414\u0435\u0432\u0438, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0434 \u0432\u0441\u0435\u0445 \u0441\u0438\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s15.38" id="s15.38" class="num">15.38</a><p>\u0423\u043C \u0434\u043B\u044F \u043B\u044E\u0434\u0435\u0439 \u2013 \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C (\u0435\u0433\u043E \u0434\u0445\u0430\u0440\u0430\u043D\u0443), \u0435\u0441\u043B\u0438 \u043E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u0432\u0435\u0447\u043D\u043E\u0433\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s15.39" id="s15.39" class="num">15.39</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0443\u043C), \u0446\u0432\u0435\u0442\u0430 \u043F\u043E\u043B\u0443\u043C\u0435\u0441\u044F\u0446\u0430, \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u044B\u0439 \u043B\u0438\u0446\u043E\u043C \u0432\u043D\u0438\u0437, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432 \u0441\u0435\u0440\u0434\u0446\u0435. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0442\u0430\u043A, \u0437\u0430 \u043C\u0435\u0441\u044F\u0446 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0421\u0432\u0435\u0442\u0430 .</p></div><div class="stanza"><a href="#s15.40" id="s15.40" class="num">15.40</a><p>\u0427\u0442\u043E \u0431\u044B \u043E\u043D \u043D\u0438 \u0432\u0438\u0434\u0435\u043B, \u0447\u0442\u043E \u0431\u044B \u043E\u043D \u043D\u0438 \u0441\u043B\u044B\u0448\u0430\u043B, \u043A\u0430\u0436\u0434\u043E\u0435 \u044D\u0442\u043E \u0437\u043D\u0430\u043D\u0438\u0435 (\u0435\u0441\u0442\u044C \u0443\u043C) -\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u0445 \u0447\u0443\u0432\u0441\u0442\u0432 .</p></div><div class="stanza"><a href="#s15.41" id="s15.41" class="num">15.41</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442, \u043A\u0430\u043A \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0432 \u043A\u0430\u0436\u0434\u043E\u043C \u0441\u0432\u043E\u0435\u043C \u0447\u0443\u0432\u0441\u0442\u0432\u0435. \u0414\u043B\u044F \u0439\u043E\u0433\u0438\u043D\u043E\u0432, \u043F\u0440\u0438\u043E\u0431\u0449\u0435\u043D\u043D\u044B\u0445 \u0439\u043E\u0433\u0435 \u044D\u0442\u043E (\u0432\u0438\u0434\u0435\u043D\u0438\u0435) \u0431\u0443\u0434\u0435\u0442 \u043E\u0442\u0447\u0435\u0442\u043B\u0438\u0432\u044B\u043C .</p></div><div class="stanza"><a href="#s15.42" id="s15.42" class="num">15.42</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u044D\u0442\u043E, \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0442\u0435\u043B\u0443, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0443\u043C\u0430 \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u043B\u0443\u043D\u044B .</p></div><div class="stanza"><a href="#s15.43" id="s15.43" class="num">15.43</a><p>\u0422\u0430\u043A\u043E\u0432\u044B \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u043F\u0435\u0441\u043D\u0435\u0439. \u0422\u0435 \u043A\u0442\u043E \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442 \u0438\u0445, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043F\u043B\u043E\u0434 \u0432\u0441\u0435\u0445 \u0447\u0443\u0432\u0441\u0442\u0432 .</p></div><div class="stanza"><a href="#s15.44" id="s15.44" class="num">15.44</a><p>(\u041E\u043D\u0438-) \u043C\u0443\u0434\u0440\u0435\u0446\u044B, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u043F\u0440\u043E\u0431\u0443\u0434\u0438\u0442\u044C \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u043E\u0442 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u041F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 (\u0447\u0443\u0432\u0441\u0442\u0432\u0430) \u0432\u0435\u0434\u0443\u0442 \u043A \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438, \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435- \u043A \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E .</p></div><div class="stanza"><a href="#s15.45" id="s15.45" class="num">15.45</a><p>\u041A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 (\u0447\u0443\u0432\u0441\u0442\u0432\u0430) \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F (\u0432\u044C\u044F\u043F\u0430\u043A\u0430), \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0443\u043C\u043E\u043C, \u0442\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u043A\u0430\u043A \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u044E\u0449\u0438\u0435, \u043E \u0412\u043E\u0437\u043B\u044E\u0431\u043B\u0435\u043D\u043D\u0430\u044F .</p></div><div class="stanza"><a href="#s15.46" id="s15.46" class="num">15.46</a><p>\u041A\u043E\u0433\u0434\u0430 (\u043E\u043D\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u044B \u043D\u0430) \u043A\u0430\u043A\u0438\u0435- \u043B\u0438\u0431\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0432\u043D\u0443\u0442\u0440\u0438 \u043A\u0430\u043A\u043E\u0433\u043E- \u043B\u0438\u0431\u043E \u043C\u0435\u0441\u0442\u0430, \u0442\u043E\u0433\u0434\u0430 \u044D\u0442\u0438 \u043C\u0435\u0441\u0442\u0430 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u043E\u043A\u043E\u0432\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s15.47" id="s15.47" class="num">15.47</a><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0447\u0443\u0432\u0441\u0442\u0432, \u0434\u0432\u0443\u0445 \u0432\u0438\u0434\u043E\u0432, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u0430\u044F \u043D\u0430 \u0447\u0438\u0441\u0442\u0443\u044E \u0438 \u043D\u0435\u0447\u0438\u0441\u0442\u0443\u044E, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u043C\u044B\u0445 \u0432 \u0443\u0447\u0435\u043D\u0438\u0438 \u0441\u0438\u0434\u0434\u0445\u0438\u0439\u043E\u0433\u0438\u0448\u0432\u0430\u0440\u0438 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430</p>',48),p=[n];function l(v,t,e,r,m,u){return i(),a("div",null,p)}var z=s(c,[["render",l]]);export{h as __pageData,z as default};
